     1→// Recruiter Dashboard & Job Management Routes
     2→const express = require('express');
     3→const pool = require('../lib/db');
     4→const { authMiddleware } = require('../lib/auth');
     5→const trustscoreService = require('../services/trustscore');
     6→const jobOptimizer = require('../services/job-optimizer');
     7→const { AuditLogger } = require('../services/auditLogger');
     8→
     9→const router = express.Router();
    10→
    11→// Middleware to require recruiter role
    12→function requireRecruiter(req, res, next) {
    13→  if (!req.user.company_id || !['recruiter', 'hiring_manager', 'admin'].includes(req.user.role)) {
    14→    return res.status(403).json({ error: 'Recruiter access required' });
    15→  }
    16→  next();
    17→}
    18→
    19→// Dashboard overview
    20→router.get('/dashboard', authMiddleware, requireRecruiter, async (req, res) => {
    21→  try {
    22→    const companyId = req.user.company_id;
    23→
    24→    // Get TrustScore
    25→    const trustScore = await trustscoreService.calculateTrustScore(companyId);
    26→
    27→    // Get job stats
    28→    const jobStats = await pool.query(`
    29→      SELECT
    30→        COUNT(*) FILTER (WHERE status = 'active') as active_jobs,
    31→        COUNT(*) FILTER (WHERE status = 'paused') as paused_jobs,
    32→        COUNT(*) FILTER (WHERE status = 'closed') as closed_jobs
    33→      FROM jobs WHERE company_id = $1
    34→    `, [companyId]);
    35→
    36→    // Get application stats
    37→    const appStats = await pool.query(`
    38→      SELECT
    39→        COUNT(*) as total_applications,
    40→        COUNT(*) FILTER (WHERE status = 'applied') as new_applications,
    41→        COUNT(*) FILTER (WHERE status = 'reviewing') as reviewing,
    42→        COUNT(*) FILTER (WHERE status = 'interviewed') as interviewed,
    43→        COUNT(*) FILTER (WHERE status = 'offered') as offered,
    44→        COUNT(*) FILTER (WHERE status = 'hired') as hired
    45→      FROM job_applications WHERE company_id = $1
    46→    `, [companyId]);
    47→
    48→    // Get upcoming interviews
    49→    const upcomingInterviews = await pool.query(`
    50→      SELECT si.id, si.scheduled_at, si.interview_type, si.status,
    51→             u.name as candidate_name, u.email as candidate_email,
    52→             j.title as job_title
    53→      FROM scheduled_interviews si
    54→      JOIN users u ON si.candidate_id = u.id
    55→      JOIN jobs j ON si.job_id = j.id
    56→      WHERE si.company_id = $1
    57→        AND si.scheduled_at > NOW()
    58→        AND si.status = 'scheduled'
    59→      ORDER BY si.scheduled_at
    60→      LIMIT 5
    61→    `, [companyId]);
    62→
    63→    // Get recent applications
    64→    const recentApps = await pool.query(`
    65→      SELECT ja.id, ja.status, ja.applied_at, ja.omniscore_at_apply,
    66→             u.name as candidate_name, u.email as candidate_email,
    67→             j.title as job_title, j.id as job_id
    68→      FROM job_applications ja
    69→      JOIN users u ON ja.candidate_id = u.id
    70→      JOIN jobs j ON ja.job_id = j.id
    71→      WHERE ja.company_id = $1
    72→      ORDER BY ja.applied_at DESC
    73→      LIMIT 10
    74→    `, [companyId]);
    75→
    76→    res.json({
    77→      success: true,
    78→      trust_score: trustScore,
    79→      job_stats: jobStats.rows[0],
    80→      application_stats: appStats.rows[0],
    81→      upcoming_interviews: upcomingInterviews.rows,
    82→      recent_applications: recentApps.rows
    83→    });
    84→  } catch (err) {
    85→    console.error('Dashboard error:', err);
    86→    res.status(500).json({ error: 'Failed to load dashboard' });
    87→  }
    88→});
    89→
    90→// Get all jobs for company
    91→router.get('/jobs', authMiddleware, requireRecruiter, async (req, res) => {
    92→  try {
    93→    const { status, limit = 50, offset = 0 } = req.query;
    94→
    95→    let query = `
    96→      SELECT j.*,
    97→             COALESCE(ja.views, 0) as views,
    98→             COALESCE(ja.applications, 0) as application_count,
    99→             COALESCE(ja.interviews_scheduled, 0) as interviews
   100→      FROM jobs j
   101→      LEFT JOIN job_analytics ja ON j.id = ja.job_id
   102→      WHERE j.company_id = $1
   103→    `;
   104→    const params = [req.user.company_id];
   105→
   106→    if (status) {
   107→      query += ` AND j.status = $${params.length + 1}`;
   108→      params.push(status);
   109→    }
   110→
   111→    query += ` ORDER BY j.created_at DESC LIMIT $${params.length + 1} OFFSET $${params.length + 2}`;
   112→    params.push(limit, offset);
   113→
   114→    const result = await pool.query(query, params);
   115→
   116→    res.json({ jobs: result.rows });
   117→  } catch (err) {
   118→    console.error('Get jobs error:', err);
   119→    res.status(500).json({ error: 'Failed to fetch jobs' });
   120→  }
   121→});
   122→
   123→// Create job with optional AI optimization
   124→router.post('/jobs', authMiddleware, requireRecruiter, async (req, res) => {
   125→  try {
   126→    const {
   127→      title, description, requirements, location, salary_range, job_type,
   128→      optimize = false // Flag to run AI optimization
   129→    } = req.body;
   130→
   131→    if (!title) {
   132→      return res.status(400).json({ error: 'Job title is required' });
   133→    }
   134→
   135→    let finalDescription = description;
   136→    let finalRequirements = requirements;
   137→    let optimizationResult = null;
   138→
   139→    // Run AI optimization if requested
   140→    if (optimize) {
   141→      try {
   142→        optimizationResult = await jobOptimizer.optimizeJobDescription({
   143→          title, description, requirements, location, salary_range, job_type,
   144→          company: req.user.company_name
   145→        });
   146→        finalDescription = optimizationResult.optimized_description || description;
   147→        finalRequirements = optimizationResult.optimized_requirements || requirements;
   148→      } catch (e) {
   149→        console.error('Job optimization error:', e);
   150→        // Continue without optimization
   151→      }
   152→    }
   153→
   154→    // Create job
   155→    const result = await pool.query(
   156→      `INSERT INTO jobs (user_id, company_id, title, company, description, requirements, location, salary_range, job_type)
   157→       VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)
   158→       RETURNING *`,
   159→      [req.user.id, req.user.company_id, title, req.user.company_name,
   160→       finalDescription, finalRequirements, location, salary_range, job_type || 'full-time']
   161→    );
   162→
   163→    const job = result.rows[0];
   164→
   165→    // Create analytics entry
   166→    await pool.query(
   167→      'INSERT INTO job_analytics (job_id) VALUES ($1)',
   168→      [job.id]
   169→    );
   170→
   171→    // Analyze and add authenticity score
   172→    try {
   173→      const analysis = await jobOptimizer.analyzeJobPosting({
   174→        title, description: finalDescription, requirements: finalRequirements,
   175→        location, salary_range, job_type, company: req.user.company_name
   176→      });
   177→
   178→      await trustscoreService.addJobAuthenticityComponent(
   179→        req.user.company_id,
   180→        job.id,
   181→        analysis.overall_score
   182→      );
   183→
   184→      res.json({
   185→        success: true,
   186→        job,
   187→        optimization: optimizationResult,
   188→        analysis,
   189→        message: optimize ? 'Job created with AI optimization!' : 'Job created successfully'
   190→      });
   191→    } catch (e) {
   192→      // Return job without analysis
   193→      res.json({ success: true, job });
   194→    }
   195→
   196→  } catch (err) {
   197→    console.error('Create job error:', err);
   198→    res.status(500).json({ error: 'Failed to create job' });
   199→  }
   200→});
   201→
   202→// Analyze job posting
   203→router.post('/jobs/analyze', authMiddleware, requireRecruiter, async (req, res) => {
   204→  try {
   205→    const analysis = await jobOptimizer.analyzeJobPosting(req.body);
   206→    res.json({ success: true, analysis });
   207→  } catch (err) {
   208→    console.error('Analyze job error:', err);
   209→    res.status(500).json({ error: 'Failed to analyze job' });
   210→  }
   211→});
   212→
   213→// Optimize job description with AI
   214→router.post('/jobs/optimize', authMiddleware, requireRecruiter, async (req, res) => {
   215→  try {
   216→    const optimized = await jobOptimizer.optimizeJobDescription(req.body);
   217→    res.json({ success: true, optimized });
   218→  } catch (err) {
   219→    console.error('Optimize job error:', err);
   220→    res.status(500).json({ error: 'Failed to optimize job' });
   221→  }
   222→});
   223→
   224→// Get salary insights
   225→router.get('/salary-insights', authMiddleware, requireRecruiter, async (req, res) => {
   226→  try {
   227→    const { title, location, experience_level } = req.query;
   228→
   229→    if (!title) {
   230→      return res.status(400).json({ error: 'Job title is required' });
   231→    }
   232→
   233→    const insights = await jobOptimizer.getSalaryInsights(title, location, experience_level);
   234→    res.json({ success: true, insights });
   235→  } catch (err) {
   236→    console.error('Salary insights error:', err);
   237→    res.status(500).json({ error: 'Failed to get salary insights' });
   238→  }
   239→});
   240→
   241→// Update job
   242→router.put('/jobs/:id', authMiddleware, requireRecruiter, async (req, res) => {
   243→  try {
   244→    const { title, description, requirements, location, salary_range, job_type, status } = req.body;
   245→
   246→    // Verify ownership
   247→    const existing = await pool.query(
   248→      'SELECT id FROM jobs WHERE id = $1 AND company_id = $2',
   249→      [req.params.id, req.user.company_id]
   250→    );
   251→
   252→    if (existing.rows.length === 0) {
   253→      return res.status(404).json({ error: 'Job not found' });
   254→    }
   255→
   256→    const result = await pool.query(
   257→      `UPDATE jobs SET
   258→        title = COALESCE($1, title),
   259→        description = COALESCE($2, description),
   260→        requirements = COALESCE($3, requirements),
   261→        location = COALESCE($4, location),
   262→        salary_range = COALESCE($5, salary_range),
   263→        job_type = COALESCE($6, job_type),
   264→        status = COALESCE($7, status),
   265→        updated_at = NOW()
   266→       WHERE id = $8
   267→       RETURNING *`,
   268→      [title, description, requirements, location, salary_range, job_type, status, req.params.id]
   269→    );
   270→
   271→    res.json({ success: true, job: result.rows[0] });
   272→  } catch (err) {
   273→    console.error('Update job error:', err);
   274→    res.status(500).json({ error: 'Failed to update job' });
   275→  }
   276→});
   277→
   278→// Get ALL applications for the company
   279→router.get('/applications', authMiddleware, requireRecruiter, async (req, res) => {
   280→  try {
   281→    const { status, job_id, limit = 100, offset = 0 } = req.query;
   282→
   283→    let query = `
   284→      SELECT ja.*,
   285→             u.name as candidate_name, u.email as candidate_email,
   286→             j.title as job_title, j.id as job_id,
   287→             os.total_score as current_omniscore, os.score_tier
   288→      FROM job_applications ja
   289→      JOIN users u ON ja.candidate_id = u.id
   290→      JOIN jobs j ON ja.job_id = j.id
   291→      LEFT JOIN omni_scores os ON u.id = os.user_id
   292→      WHERE ja.company_id = $1
   293→    `;
   294→    const params = [req.user.company_id];
   295→
   296→    if (status) {
   297→      query += ` AND ja.status = $${params.length + 1}`;
   298→      params.push(status);
   299→    }
   300→
   301→    if (job_id) {
   302→      query += ` AND ja.job_id = $${params.length + 1}`;
   303→      params.push(job_id);
   304→    }
   305→
   306→    query += ` ORDER BY ja.applied_at DESC LIMIT $${params.length + 1} OFFSET $${params.length + 2}`;
   307→    params.push(limit, offset);
   308→
   309→    const result = await pool.query(query, params);
   310→
   311→    res.json({ applications: result.rows });
   312→  } catch (err) {
   313→    console.error('Get applications error:', err);
   314→    res.status(500).json({ error: 'Failed to fetch applications' });
   315→  }
   316→});
   317→
   318→// Update application status (alternative route)
   319→router.put('/applications/:id/status', authMiddleware, requireRecruiter, async (req, res) => {
   320→  try {
   321→    const { status } = req.body;
   322→
   323→    // Verify application belongs to company
   324→    const existing = await pool.query(
   325→      'SELECT id, job_id, candidate_id FROM job_applications WHERE id = $1 AND company_id = $2',
   326→      [req.params.id, req.user.company_id]
   327→    );
   328→
   329→    if (existing.rows.length === 0) {
   330→      return res.status(404).json({ error: 'Application not found' });
