   332→
   333→    const result = await pool.query(
   334→      `UPDATE job_applications SET status = $1, updated_at = NOW() WHERE id = $2 RETURNING *`,
   335→      [status, req.params.id]
   336→    );
   337→
   338→    // Audit log
