   528→// Schedule interview
   529→router.post('/interviews/schedule', authMiddleware, requireRecruiter, async (req, res) => {
   530→  try {
   531→    const {
   532→      job_id, candidate_id, scheduled_at, duration_minutes = 60,
   533→      interview_type = 'video', meeting_link, notes
   534→    } = req.body;
   535→
   536→    if (!job_id || !candidate_id || !scheduled_at) {
   537→      return res.status(400).json({ error: 'Job, candidate, and scheduled time are required' });
   538→    }
   539→
   540→    // Verify job belongs to company
   541→    const job = await pool.query(
